// src/load.ts
var EMPTY_WORKINGDIR_PATH_ERROR = "Error: Cannot load from empty working directory path";
var INVALID_PATH_ERROR = "Error: Invalid path to element on filesystem";
function convertYamlFilePathToElementPath(filePath) {
  if (filePath.slice(-10) === "_this.yaml") {
    const elementPath = filePath.split("/").slice(0, -1).join(".");
    return elementPath;
  } else {
    const elementPath = filePath.slice(0, -5).replace("/", ".");
    return elementPath;
  }
}
function loadYaml(filePath, elementPath, depth) {
  const thisYamlContent = fs2.readFileSync(filePath, "utf8");
  let yamlAsJsObj = yaml2.load(thisYamlContent);
  const keys = Object.keys(yamlAsJsObj);
  if (depth !== 0) {
    if (depth > 0) {
      depth = depth - 1;
    }
    keys.forEach((key) => {
      if (typeof yamlAsJsObj[key] == "string") {
        if (doubleParenthesesRegEx.test(yamlAsJsObj[key])) {
          const dirPath = filePath.split("/").slice(0, -1).join("/");
          const aComplexDataTypeFilePath = trimDoubleParentheses(
            yamlAsJsObj[key]
          );
          if (aComplexDataTypeFilePath.slice(-5) === ".yaml") {
            const newElementPath = convertYamlFilePathToElementPath(
              aComplexDataTypeFilePath
            );
            yamlAsJsObj[key] = load(
              dirPath,
              newElementPath,
              depth
            ).element;
          } else {
            const newFilePathToLoad = path2.join(
              dirPath,
              aComplexDataTypeFilePath
            );
            const aComplexDataTypeContent = fs2.readFileSync(
              newFilePathToLoad,
              "utf-8"
            );
            yamlAsJsObj[key] = aComplexDataTypeContent;
          }
        }
      }
    });
  }
  return new YdsResult(true, yamlAsJsObj, elementPath);
}
function load(workingDirectoryPath, elementPath, depth = -1) {
  if (workingDirectoryPath === "") {
    return new YdsResult(false, null, EMPTY_WORKINGDIR_PATH_ERROR);
  } else {
    let elementPathInfo = getElementPathInfo(workingDirectoryPath, elementPath);
    switch (elementPathInfo.type) {
      case 1 /* empty */:
      case 2 /* shortToObject */:
      case 3 /* shortToList */:
      case 6 /* hierarchicalToObject */:
      case 7 /* hierarchicalToList */:
        return loadYaml(elementPathInfo.data, elementPath, depth);
      case 5 /* shortToSimple */:
      case 9 /* hierarchicalToSimple */:
        return new YdsResult(true, elementPathInfo.data, elementPath);
      case 4 /* shortToComplexString */:
      case 8 /* hierarchicalToComplexString */:
        const elementContent = fs2.readFileSync(elementPathInfo.data, "utf-8");
        return new YdsResult(true, elementContent, elementPath);
      case 0 /* invalid */:
        break;
    }
    return new YdsResult(
      false,
      null,
      INVALID_PATH_ERROR + " [" + workingDirectoryPath + " | " + elementPath + "]"
    );
  }
}

