          deleteChildFromParentElement(parentElement, elementPathInfo.keyName);
          const parentElementOfObjectContentsToStore = yaml4.dump(parentElement);
          fs4.writeFileSync(
            parentFilePath,
            parentElementOfObjectContentsToStore
          );
